"""
Oceanic plate object. Requires properties `model` and `coordinates`.
"""
Base.@kwdef struct OceanicPlate <: AbstractFeature
    coordinates::Vector{Vector{Float64}} = Vector{Float64}[]  # An array of 2d Points representing an array of coordinates where the feature is located.
    interpolation::String = "global"  # What type of interpolation should be used to enforce the minimum points per distance parameter. Options are 'global' and 'continuous monotone spline' interpolation. If this value is set to global, the global value for interpolation is used. This option is deprecated and will be removed in a future release.
    max_depth::Any = 1.7976931348623157e308  # The depth to which this feature is present (Float64, or a per-coordinate override structure as written in the .wb file)
    min_depth::Any = 0.0  # The depth from which this feature is present (Float64, or a per-coordinate override structure as written in the .wb file)
    name::String = ""  # The name which the user has given to the feature. This is mostly used for documentation purposes, and should in most cases be unique, although this is not enforced.
    tag::String = ""  # A tag which can be given to a feature. This is meant to categorize different features. If the tag is not provided or empty, it is set to the model name.
    composition_models::Vector{AbstractCompositionModel} = AbstractCompositionModel[]
    grains_models::Vector{AbstractGrainsModel} = AbstractGrainsModel[]
    temperature_models::Vector{AbstractTemperatureModel} = AbstractTemperatureModel[]
    topography_models::Vector{AbstractTopographyModel} = AbstractTopographyModel[]
    velocity_models::Vector{AbstractVelocityModel} = AbstractVelocityModel[]
end

function to_dict(x::OceanicPlate)
    d = OrderedDict{String,Any}()
    d["model"] = "oceanic plate"
    _set_if_nondefault!(d, "coordinates", x.coordinates, Vector{Float64}[])
    _set_if_nondefault!(d, "interpolation", x.interpolation, "global")
    _set_if_nondefault!(d, "max depth", x.max_depth, 1.7976931348623157e308)
    _set_if_nondefault!(d, "min depth", x.min_depth, 0.0)
    _set_if_nondefault!(d, "name", x.name, "")
    _set_if_nondefault!(d, "tag", x.tag, "")
    isempty(x.composition_models) || (d["composition models"] = to_dict.(x.composition_models))
    isempty(x.grains_models) || (d["grains models"] = to_dict.(x.grains_models))
    isempty(x.temperature_models) || (d["temperature models"] = to_dict.(x.temperature_models))
    isempty(x.topography_models) || (d["topography models"] = to_dict.(x.topography_models))
    isempty(x.velocity_models) || (d["velocity models"] = to_dict.(x.velocity_models))
    return d
end

function from_dict(::Type{OceanicPlate}, d::AbstractDict)
    kwargs = Dict{Symbol,Any}()
    haskey(d, "coordinates") && (kwargs[:coordinates] = _coerce(Vector{Vector{Float64}}, d["coordinates"]))
    haskey(d, "interpolation") && (kwargs[:interpolation] = _coerce(String, d["interpolation"]))
    haskey(d, "max depth") && (kwargs[:max_depth] = _coerce(Any, d["max depth"]))
    haskey(d, "min depth") && (kwargs[:min_depth] = _coerce(Any, d["min depth"]))
    haskey(d, "name") && (kwargs[:name] = _coerce(String, d["name"]))
    haskey(d, "tag") && (kwargs[:tag] = _coerce(String, d["tag"]))
    haskey(d, "composition models") && (kwargs[:composition_models] = [model_from_dict("oceanic plate", "composition models", m) for m in d["composition models"]])
    haskey(d, "grains models") && (kwargs[:grains_models] = [model_from_dict("oceanic plate", "grains models", m) for m in d["grains models"]])
    haskey(d, "temperature models") && (kwargs[:temperature_models] = [model_from_dict("oceanic plate", "temperature models", m) for m in d["temperature models"]])
    haskey(d, "topography models") && (kwargs[:topography_models] = [model_from_dict("oceanic plate", "topography models", m) for m in d["topography models"]])
    haskey(d, "velocity models") && (kwargs[:velocity_models] = [model_from_dict("oceanic plate", "velocity models", m) for m in d["velocity models"]])
    return OceanicPlate(; kwargs...)
end

