    haskey(d, "name") && (kwargs[:name] = _coerce(String, d["name"]))
    haskey(d, "rotation angles") && (kwargs[:rotation_angles] = _coerce(Vector{Float64}, d["rotation angles"]))
    haskey(d, "semi-major axis") && (kwargs[:semi_major_axis] = _coerce(Vector{Float64}, d["semi-major axis"]))
