    haskey(d, "composition models") && (kwargs[:composition_models] = [model_from_dict("plume", "composition models", m) for m in d["composition models"]])
    haskey(d, "grains models") && (kwargs[:grains_models] = [model_from_dict("plume", "grains models", m) for m in d["grains models"]])
    haskey(d, "temperature models") && (kwargs[:temperature_models] = [model_from_dict("plume", "temperature models", m) for m in d["temperature models"]])
    haskey(d, "velocity models") && (kwargs[:velocity_models] = [model_from_dict("plume", "velocity models", m) for m in d["velocity models"]])
    return Plume(; kwargs...)
end

"""
Gaussian temperature model. The temperature is interpolated between the plume center and margin (as defined by the plume feature) using a Gaussian function: T(r) = T_center(z) exp(-r^2/(2 sigma^2). The temperature at the plume centerline T_center can be changed with depth by defining an array of depths and centerline temperatures, and temperature is interpolated linearly with depth. Similarly, the sigma of the Gaussian function (relative to the width of the plume as given by the plume feature) can be changed with depth. Temperature is always interpolated in a horizonzal/radial plane, except for the plume head: If the first depth of the plume centerline and the minimum depth of the plume feature are different, an ellipsoidal plume head is created in this depth range. Within this plume head, temperature is interpolated radially, i.e., depending on the distance from the center of the ellipsoid.
"""
Base.@kwdef struct PlumeGaussianTemperature <: AbstractTemperatureModel
    centerline_temperatures::Vector{Float64} = Float64[]  # The temperature at the center of this feature in degree Kelvin.If the value is below zero, then an adiabatic temperature is used.
    depths::Vector{Float64} = Float64[]  # The list of depths where both the temperature in the center of the plume and the width of the temperature anomaly in terms of the sigma of a Gaussian function can be provided. Temperature is interpolated linearly in vertical direction between these depths. Units: m.
    gaussian_sigmas::Vector{Float64} = Float64[]  # The sigma (standard deviation) of the Gaussian function used to compute the temperature distribution within the plume. This sigma is non-dimensional, i.e. it is defined relative to the distance between the plume center and margin as defined by the plume feature. Choosing a sigma of 1 therefore means that the temperature at the plume margin is set to a fraction of 1/sqrt(e) (approx. 0.61) of the centerline temperature. To achieve a smoother transition between the plume temperature and the outside temperature a smaller values has to be chosen for the gaussian sigmas.
    operation::String = "replace"  # Whether the value should replace any value previously defined at this location (replace), add the value to the previously define value (add) or subtract the value to the previously define value (subtract).
end

function to_dict(x::PlumeGaussianTemperature)
    d = OrderedDict{String,Any}()
    d["model"] = "gaussian"
    _set_if_nondefault!(d, "centerline temperatures", x.centerline_temperatures, Float64[])
    _set_if_nondefault!(d, "depths", x.depths, Float64[])
    _set_if_nondefault!(d, "gaussian sigmas", x.gaussian_sigmas, Float64[])
    _set_if_nondefault!(d, "operation", x.operation, "replace")
    return d
end

function from_dict(::Type{PlumeGaussianTemperature}, d::AbstractDict)
    kwargs = Dict{Symbol,Any}()
    haskey(d, "centerline temperatures") && (kwargs[:centerline_temperatures] = _coerce(Vector{Float64}, d["centerline temperatures"]))
    haskey(d, "depths") && (kwargs[:depths] = _coerce(Vector{Float64}, d["depths"]))
    haskey(d, "gaussian sigmas") && (kwargs[:gaussian_sigmas] = _coerce(Vector{Float64}, d["gaussian sigmas"]))
    haskey(d, "operation") && (kwargs[:operation] = _coerce(String, d["operation"]))
    return PlumeGaussianTemperature(; kwargs...)
end

