"""
TianWaterContent compositional model. Sets bound water content as a compositional field. The returned water content is based on the the temperature and pressure at a point within the world. Currently, the bound water content can be determined for four different lithologies: 'sediment', mid-ocean ridge basalt ('MORB'), 'gabbro', and 'peridotite', using parameterized phase diagrams from Tian et al., 2019 (https://doi.org/10.1029/2019GC008488). The pressure is lithostatic, calculated with a constant user defined density, and is limited by a user defined cutoff pressure (in GPa) for each lithology. This is required because the parameterization breaks down at large pressures. Recommended cutoff pressures are 10 GPa is used for 'peridotite', 26 GPa is used for 'gabbro', 16 GPa is used for 'MORB', and 1 GPa is used for 'sediment'.
"""
Base.@kwdef struct SubductingPlateTianWaterContentComposition <: AbstractCompositionModel
    compositions::Vector{Int} = Int[]  # A list with the labels of the composition which are present there.
    cutoff_pressure::Float64 = 10.0  # The upper bound for the pressure, in GPa, for the specified lithology in the Tian parameterization. This is necessary because the parameterization breaks down for high pressures. It is recommended that 10 GPa is used for 'peridotite', 26 GPa is used for 'gabbro', 16 GPa is used for 'MORB', and 1 GPa is used for 'sediment'.
    density::Float64 = 3000.0  # The reference density used for determining the lithostatic pressure for calculating the bound water content.
    initial_water_content::Float64 = 5.0  # The value of the initial water content (in wt%) for the lithology at the trench. This represents the max value applied to this lithology.
    lithology::String = "peridotite"  # The lithology used to determine which polynomials to use for calculating the water content. Valid options are: 'sediment', 'MORB', 'gabbro', and 'peridotite'.
    max_distance_slab_top::Float64 = 1.7976931348623157e308  # todo The depth in meters to which the composition of this feature is present.
    min_distance_slab_top::Float64 = 0.0  # todo The depth in meters from which the composition of this feature is present.
    operation::String = "replace"  # Whether the value should replace any value previously defined at this location (replace) or add the value to the previously define value. Replacing implies that all compositions not explicitly defined are set to zero. To only replace the defined compositions use the replace only defined option.
end

function to_dict(x::SubductingPlateTianWaterContentComposition)
    d = OrderedDict{String,Any}()
    d["model"] = "tian water content"
    _set_if_nondefault!(d, "compositions", x.compositions, Int[])
    _set_if_nondefault!(d, "cutoff pressure", x.cutoff_pressure, 10.0)
    _set_if_nondefault!(d, "density", x.density, 3000.0)
    _set_if_nondefault!(d, "initial water content", x.initial_water_content, 5.0)
    _set_if_nondefault!(d, "lithology", x.lithology, "peridotite")
    _set_if_nondefault!(d, "max distance slab top", x.max_distance_slab_top, 1.7976931348623157e308)
    _set_if_nondefault!(d, "min distance slab top", x.min_distance_slab_top, 0.0)
    _set_if_nondefault!(d, "operation", x.operation, "replace")
    return d
end

function from_dict(::Type{SubductingPlateTianWaterContentComposition}, d::AbstractDict)
    kwargs = Dict{Symbol,Any}()
    haskey(d, "compositions") && (kwargs[:compositions] = _coerce(Vector{Int}, d["compositions"]))
    haskey(d, "cutoff pressure") && (kwargs[:cutoff_pressure] = _coerce(Float64, d["cutoff pressure"]))
    haskey(d, "density") && (kwargs[:density] = _coerce(Float64, d["density"]))
    haskey(d, "initial water content") && (kwargs[:initial_water_content] = _coerce(Float64, d["initial water content"]))
    haskey(d, "lithology") && (kwargs[:lithology] = _coerce(String, d["lithology"]))
    haskey(d, "max distance slab top") && (kwargs[:max_distance_slab_top] = _coerce(Float64, d["max distance slab top"]))
