    _set_if_nondefault!(d, "operation", x.operation, "replace")
    _set_if_nondefault!(d, "potential mantle temperature", x.potential_mantle_temperature, -1.0)
    _set_if_nondefault!(d, "reference model name", x.reference_model_name, "half space model")
    _set_if_nondefault!(d, "ridge coordinates", x.ridge_coordinates, Any[])
    _set_if_nondefault!(d, "specific heat", x.specific_heat, -1.0)
    _set_if_nondefault!(d, "spreading velocity", x.spreading_velocity, 0.05)
    _set_if_nondefault!(d, "subducting velocity", x.subducting_velocity, 0.05)
    _set_if_nondefault!(d, "taper distance", x.taper_distance, 100000.0)
    _set_if_nondefault!(d, "thermal conductivity", x.thermal_conductivity, 3.3)
    _set_if_nondefault!(d, "thermal diffusivity", x.thermal_diffusivity, -1.0)
    _set_if_nondefault!(d, "thermal expansion coefficient", x.thermal_expansion_coefficient, -1.0)
    return d
end

function from_dict(::Type{SubductingPlateSegmentMassConservingTemperature}, d::AbstractDict)
    kwargs = Dict{Symbol,Any}()
    haskey(d, "adiabatic heating") && (kwargs[:adiabatic_heating] = _coerce(Bool, d["adiabatic heating"]))
    haskey(d, "apply spline") && (kwargs[:apply_spline] = _coerce(Bool, d["apply spline"]))
