function to_dict(x::SubductingPlateSegmentUniformComposition)
    d = OrderedDict{String,Any}()
    d["model"] = "uniform"
    _set_if_nondefault!(d, "compositions", x.compositions, Int[])
    _set_if_nondefault!(d, "fractions", x.fractions, Float64[])
    _set_if_nondefault!(d, "max distance slab top", x.max_distance_slab_top, 1.7976931348623157e308)
    _set_if_nondefault!(d, "min distance slab top", x.min_distance_slab_top, 0.0)
    _set_if_nondefault!(d, "operation", x.operation, "replace")
    return d
end

function from_dict(::Type{SubductingPlateSegmentUniformComposition}, d::AbstractDict)
    kwargs = Dict{Symbol,Any}()
    haskey(d, "compositions") && (kwargs[:compositions] = _coerce(Vector{Int}, d["compositions"]))
    haskey(d, "fractions") && (kwargs[:fractions] = _coerce(Vector{Float64}, d["fractions"]))
    haskey(d, "max distance slab top") && (kwargs[:max_distance_slab_top] = _coerce(Float64, d["max distance slab top"]))
    haskey(d, "min distance slab top") && (kwargs[:min_distance_slab_top] = _coerce(Float64, d["min distance slab top"]))
    haskey(d, "operation") && (kwargs[:operation] = _coerce(String, d["operation"]))
    return SubductingPlateSegmentUniformComposition(; kwargs...)
end

const FEATURE_TYPE_FOR_MODEL = Dict{String,Type}(
    "continental plate" => ContinentalPlate,
    "fault" => Fault,
    "mantle layer" => MantleLayer,
    "oceanic plate" => OceanicPlate,
    "plume" => Plume,
    "subducting plate" => SubductingPlate,
)

function feature_from_dict(d::AbstractDict)
    T = FEATURE_TYPE_FOR_MODEL[d["model"]]
    return from_dict(T, d)
end

